import{_ as t,o,c as a,h as r}from"./chunks/framework.DLS2G4kP.js";const u=JSON.parse('{"title":"Design Principles","description":"","frontmatter":{},"headers":[],"relativePath":"guidance/principles.md","filePath":"guidance/principles.md"}'),i={name:"guidance/principles.md"};function s(n,e,d,l,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="design-principles" tabindex="-1">Design Principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design Principles&quot;">​</a></h1><p>These principles guide every decision we make in the Cobalt Design System — from token naming to component APIs. When trade-offs arise, use these principles to break the tie.</p><hr><h2 id="_1-clarity-over-cleverness" tabindex="-1">1. Clarity over cleverness <a class="header-anchor" href="#_1-clarity-over-cleverness" aria-label="Permalink to &quot;1. Clarity over cleverness&quot;">​</a></h2><p>Interfaces should be immediately understandable. Avoid novel interaction patterns when a conventional one will do. Every element on screen should have a clear purpose.</p><table tabindex="0"><thead><tr><th>Do</th><th>Don&#39;t</th></tr></thead><tbody><tr><td>Use a standard dropdown for selecting a country.</td><td>Build a custom globe widget that requires users to spin and click.</td></tr><tr><td>Label buttons with explicit actions like &quot;Save draft.&quot;</td><td>Use ambiguous labels like &quot;Go&quot; or icon-only buttons without tooltips.</td></tr></tbody></table><blockquote><p><strong>Guiding question:</strong> Would a first-time user understand this without instructions?</p></blockquote><hr><h2 id="_2-consistency-breeds-trust" tabindex="-1">2. Consistency breeds trust <a class="header-anchor" href="#_2-consistency-breeds-trust" aria-label="Permalink to &quot;2. Consistency breeds trust&quot;">​</a></h2><p>Reuse the same patterns, tokens, and language throughout the product. Consistent experiences reduce cognitive load and build user confidence.</p><table tabindex="0"><thead><tr><th>Do</th><th>Don&#39;t</th></tr></thead><tbody><tr><td>Use <code>co-button</code> with the <code>variant=&quot;primary&quot;</code> attribute for all primary actions.</td><td>Style ad-hoc primary buttons with custom CSS in individual pages.</td></tr><tr><td>Follow the established spacing scale (<code>--co-space-200</code>, <code>--co-space-300</code>).</td><td>Introduce one-off spacing values like <code>13px</code> or <code>1.15rem</code>.</td></tr></tbody></table><blockquote><p><strong>Guiding question:</strong> Have we solved this problem before? If so, reuse that solution.</p></blockquote><hr><h2 id="_3-accessible-by-default" tabindex="-1">3. Accessible by default <a class="header-anchor" href="#_3-accessible-by-default" aria-label="Permalink to &quot;3. Accessible by default&quot;">​</a></h2><p>Accessibility is not an enhancement — it is a baseline requirement. Every Cobalt component ships with proper ARIA attributes, keyboard navigation, and color contrast ratios that meet WCAG 2.2 AA.</p><table tabindex="0"><thead><tr><th>Do</th><th>Don&#39;t</th></tr></thead><tbody><tr><td>Rely on Cobalt&#39;s built-in focus management in <code>co-dialog</code>.</td><td>Remove focus outlines for aesthetic reasons.</td></tr><tr><td>Provide visible labels for all form fields using <code>co-form-field</code>.</td><td>Use placeholder text as the only label.</td></tr></tbody></table><blockquote><p><strong>Guiding question:</strong> Can every user — regardless of ability or device — complete this task?</p></blockquote><hr><h2 id="_4-composable-not-monolithic" tabindex="-1">4. Composable, not monolithic <a class="header-anchor" href="#_4-composable-not-monolithic" aria-label="Permalink to &quot;4. Composable, not monolithic&quot;">​</a></h2><p>Components should do one thing well and combine easily with other components. Avoid building mega-components that try to handle every use case internally.</p><table tabindex="0"><thead><tr><th>Do</th><th>Don&#39;t</th></tr></thead><tbody><tr><td>Compose <code>co-card</code>, <code>co-avatar</code>, and <code>co-badge</code> to build a user profile card.</td><td>Create a <code>co-user-profile-card</code> that bundles avatar, badge, and layout logic.</td></tr><tr><td>Use slots and named slots to allow content projection.</td><td>Require deeply nested configuration objects to control rendering.</td></tr></tbody></table><blockquote><p><strong>Guiding question:</strong> Can this component be useful outside the context it was designed for?</p></blockquote><hr><h2 id="_5-performance-matters" tabindex="-1">5. Performance matters <a class="header-anchor" href="#_5-performance-matters" aria-label="Permalink to &quot;5. Performance matters&quot;">​</a></h2><p>Users notice when an interface feels sluggish. Cobalt components are tree-shakable, lazy-loadable, and optimized for minimal runtime overhead. Design decisions should respect performance budgets.</p><table tabindex="0"><thead><tr><th>Do</th><th>Don&#39;t</th></tr></thead><tbody><tr><td>Import only the components you use: <code>import &#39;@cobalt/co-button&#39;</code>.</td><td>Import the entire library: <code>import &#39;@cobalt/cobalt&#39;</code>.</td></tr><tr><td>Use <code>co-virtual-scroll</code> for lists with more than 100 items.</td><td>Render thousands of DOM nodes and rely on the browser to cope.</td></tr></tbody></table><blockquote><p><strong>Guiding question:</strong> Does this decision keep the bundle under budget and the frame rate above 60 fps?</p></blockquote><hr><h2 id="_6-progressive-disclosure" tabindex="-1">6. Progressive disclosure <a class="header-anchor" href="#_6-progressive-disclosure" aria-label="Permalink to &quot;6. Progressive disclosure&quot;">​</a></h2><p>Show only what the user needs at each step. Hide advanced options behind expandable sections, secondary panels, or progressive workflows. Reduce upfront complexity without removing capability.</p><table tabindex="0"><thead><tr><th>Do</th><th>Don&#39;t</th></tr></thead><tbody><tr><td>Place advanced filters inside a <code>co-expandable</code> section labeled &quot;More filters.&quot;</td><td>Display 20 filter controls on initial page load.</td></tr><tr><td>Use <code>co-stepper</code> to break a long form into logical steps.</td><td>Present a single scrolling form with 30 fields.</td></tr></tbody></table><blockquote><p><strong>Guiding question:</strong> What is the minimum the user needs to see right now to take the next action?</p></blockquote><hr><h2 id="applying-the-principles" tabindex="-1">Applying the principles <a class="header-anchor" href="#applying-the-principles" aria-label="Permalink to &quot;Applying the principles&quot;">​</a></h2><p>When reviewing a design or pull request, reference these principles by number. For example:</p><blockquote><p>&quot;This custom dropdown conflicts with <strong>Principle 1 (Clarity)</strong> and <strong>Principle 2 (Consistency)</strong> — let&#39;s use <code>co-select</code> instead.&quot;</p></blockquote><p>This shared vocabulary keeps discussions objective and productive.</p>',37)])])}const b=t(i,[["render",s]]);export{u as __pageData,b as default};
